void _flushAnnouncementQueueBestEffort({
  required String ownerUid,
}) {
  unawaited(
    _queueFlushOrchestrator
        .flushAll(ownerUid: ownerUid)
        .then<void>((_) {})
        .catchError((_) {
      debugPrint(
        'Announcement queue flush skipped due to transient failure.',
      );
    }),
  );
}

